"use strict";(self.webpackChunkblog=self.webpackChunkblog||[]).push([[537],{639:function(t,e,o){o.r(e),o.d(e,{frontMatter:function(){return s},contentTitle:function(){return u},metadata:function(){return l},assets:function(){return h},toc:function(){return d},default:function(){return m}});var a=o(7462),n=o(3366),i=(o(7294),o(3905)),r=["components"],s={slug:"minimum-viable-product",title:"Minimum Viable Product",tags:["Product development","MVP","RAT"]},u=void 0,l={permalink:"/minimum-viable-product",source:"@site/blog/2022-02-21-minimum-viable-product.md",title:"Minimum Viable Product",description:"In fall 2021 I did an internal presentation about some of the learnings I had during my first two years at Unity Technologies. This post covers the first topic of that presentation; the Minimum Viable Product (MVP).",date:"2022-02-21T00:00:00.000Z",formattedDate:"February 21, 2022",tags:[{label:"Product development",permalink:"/tags/product-development"},{label:"MVP",permalink:"/tags/mvp"},{label:"RAT",permalink:"/tags/rat"}],readingTime:3.37,truncated:!0,authors:[],nextItem:{title:"Do Repeat Yourself",permalink:"/do-repeat-yourself"}},h={authorsImageUrls:[]},d=[],c={toc:d};function m(t){var e=t.components,o=(0,n.Z)(t,r);return(0,i.kt)("wrapper",(0,a.Z)({},c,o,{components:e,mdxType:"MDXLayout"}),(0,i.kt)("p",null,"In fall 2021 I did an internal presentation about some of the learnings I had during my first two years at ",(0,i.kt)("a",{parentName:"p",href:"https://unity.com/"},"Unity Technologies"),". This post covers the first topic of that presentation; the Minimum Viable Product (MVP)."),(0,i.kt)("p",null,"At Unity I've been building a new web interface for an internal CI (Continuous Integration) service. This has been a profound learning experience for me; I\u2019m a much better developer today than I was two years ago, and I\u2019ve learned a lot in terms of product development.\nOne of the concepts I didn't know that much about is the MVP, which is a well-known product development term. I already knew the abbreviation, and thought that I knew what it was about, due to the (seemingly) self-explanatory name.\nBut assumptions are dangerous, which is certainly the case for the MVP, a commonly misunderstood and misused term."),(0,i.kt)("p",null,"Let's try to understand the different parts first:"),(0,i.kt)("ul",null,(0,i.kt)("li",{parentName:"ul"},(0,i.kt)("strong",{parentName:"li"},"Minimum"),": the least or smallest amount or quantity possible."),(0,i.kt)("li",{parentName:"ul"},(0,i.kt)("strong",{parentName:"li"},"Viable"),": capable of working successfully. Able to work as intended."),(0,i.kt)("li",{parentName:"ul"},(0,i.kt)("strong",{parentName:"li"},"Product"),": something that is made or grown to be sold or used (in this case obviously software products).")),(0,i.kt)("p",null,"By combining those words you might intuitively end up with a definition similar to this:"),(0,i.kt)("blockquote",null,(0,i.kt)("p",{parentName:"blockquote"},"a product of the smallest amount possible which is able to work as intended.")),(0,i.kt)("p",null,"So now we know all about the MVP, and can use it for our product?\nNot a good idea.\nI've found the MVP to be tricky, because it has a catchy and prescriptive name. You easily end up thinking you know what it's about even if you don't."),(0,i.kt)("hr",{className:"narrow-hr"}),(0,i.kt)("p",null,"What is the MVP about then? According to Wikipedia, the MVP has been around since 2001, where it was coined and defined by Frank Robinson. It's all about how to nail your first release of a product, but it's surprisingly easy to get wrong. I really like Eric Ries' definition (many do), which is outlined in his famous book, ",(0,i.kt)("a",{parentName:"p",href:"http://theleanstartup.com/"},"The Lean Startup by Eric Ries"),":"),(0,i.kt)("blockquote",null,(0,i.kt)("p",{parentName:"blockquote"},"Version of a new product, which allows a team to collect the maximum amount of validated learning about customers with the least effort.")),(0,i.kt)("p",null,"This definition captures why you would want to use an MVP: we want to learn as much as we can about customers and our product with the least effort. A keyword here is ",(0,i.kt)("em",{parentName:"p"},"learning"),". Your MVP can easily become synonymous with the first release of your product, and you\u2019re missing out if it does. Products fail because of assumptions that aren\u2019t true - and if you find out too late, or never, your product is likely to fail."),(0,i.kt)("p",null,"One of the core challenges is deciding how minimal your MVP should be. This goes hand in hand with viability. You want something that can be put into the hands of users, and elicit real feedback and learning, which can be used to correct the path you\u2019re on. But you do not need a polished product to elicit this feedback. In fact, you want to avoid polishing something that is likely to change drastically. You should instead focus on viability, and the viability of your product depends on the assumptions you have about the product. You might actually favour the newer kid on the block, the ",(0,i.kt)("a",{parentName:"p",href:"https://hackernoon.com/the-mvp-is-dead-long-live-the-rat-233d5d16ab02"},"Riskiest Assumption Test (RAT)"),", over the MVP, because it puts a stronger focus on testing your assumptions about a product."),(0,i.kt)("hr",{className:"narrow-hr"}),(0,i.kt)("p",null,"Regardless of which of those you choose, you should narrow down on the assumptions that can make or break your product. Some of these assumptions might not be unique to your product and/or can be validated with research, UX or other means. But you are likely to have assumptions that are unique to your product, and which will have to hold true for your product to succeed. If you do not, then an MVP/RAT might not even be the correct tool for you. If you do, you\u2019re gonna be much more likely to succeed if you put your assumptions to the test, and learn as early as possible."))}m.isMDXComponent=!0}}]);